import Foundation
import CryptoSwift

struct PrivateKey {
    let d: BigInteger
}

struct PublicKey {
    let rsa: RSA
    let n: BigInteger
}

struct Transaction {
    let inputAddress: String
    let outputAddress: String
    let amount: Double
    var signature: Data?
}

extension Transaction {
    func sign(privateKey: PrivateKey) -> Bool {
        let message = "\(inputAddress)\(outputAddress)\(amount)"
        let hash = SHA256.hash(data: message.data(using: .utf8)!)

        let signature = rsaSignature(hash, privateKey: privateKey)
        self.signature = signature
        return true
    }

    func isValidSignature() -> Bool {
        guard let signatureData = signature else { return false }
        let message = "\(inputAddress)\(outputAddress)\(amount)"
        let messageHash = SHA256.hash(data: message.data(using: .utf8)!)

        if RSA.verify(messageHash, signatureData, publicKey: publicKey) {
            return true
        } else {
            return false
        }
    }

    private static func rsaSignature(_ data: Data, privateKey: PrivateKey) -> Data? {
        let rsa = RSA(publicKey: PublicKey(rsa: RSA(), n: BigInteger(Data(base64Encoded: publicKeyString)!)), privateKey: RSA(n: privateKey.d))
        var signatureBytes: [UInt8] = []

        if let rsassaPssSignature = try? rsa.sign(msg: data, padding: .rsassaPssMsb(saltLength: 32, hash: .sha256)) {
            signatureBytes = rsassaPssSignature
        } else {
            let signatureBytes = try? rsa.sign(data, padding: .pkcs1OAEPWithSHA256AndMGF1Padding)
            return Data(bytes: signatureBytes!)
        }

        return Data(bytes: signatureBytes)
    }
}

